def getNeighbors(data, i, epsilon):
 neighbors = []
 for j in range(len(data)):
 if i != j and np.linalg.norm(data[i] - data[j]) <= epsilon:
 neighbors.append(j)
 return neighbors

def expandCluster(data, i, neighbors, cluster, epsilon, minPts, visited):
 cluster.append(data[i])
 for j in neighbors:
 if not visited[j]:
 visited[j] = True
 newNeighbors = getNeighbors(data, j, epsilon)
 if len(newNeighbors) >= minPts:
 neighbors.extend(newNeighbors)
 if data[j] not in cluster:
