import java.util.ArrayList;
import java.util.List;

public class DBSCAN {
 public static List<List<double[]>> dbscan(double[][] data, double epsilon, int minPts) {
 List<List<double[]>> clusters = new ArrayList<>();
 List<double[]> noise = new ArrayList<>();
 boolean[] visited = new boolean[data.length];

 for (int i = 0; i < data.length; i++) {
 if (!visited[i]) {
 visited[i] = true;
 List<Integer> neighbors = getNeighbors(data, i, epsilon);
 if (neighbors.size() >= minPts) {
 List<double[]> cluster = new ArrayList<>();
 expandCluster(data, i, neighbors, cluster, epsilon, minPts, visited);
 clusters.add(cluster);
 } else {
 noise.add(data[i]);
 }
 }
 }
 return clusters;
 }

 public static List<Integer> getNeighbors(double[][] data, int i, double epsilon) {
 List<Integer> neighbors = new ArrayList<>();
 for (int j = 0; j < data.length; j++) {
 if (i != j && distance(data[i], data[j]) <= epsilon) {
 neighbors.add(j);
 }
 }
 return neighbors;
 }

 public static void expandCluster(double[][] data, int i, List<Integer> neighbors, List<double[]> cluster, double epsilon, int minPts, boolean[] visited) {
 cluster.add(data[i]);
 for (int j : neighbors) {
 if (!visited[j]) {
 visited[j] = true;
 List<Integer> newNeighbors = getNeighbors(data, j, epsilon);
 if (newNeighbors.size() >= minPts) {
 neighbors.addAll(newNeighbors);
 }
 }
 if (!cluster.contains(data[j])) {
 cluster.add(data[j]);
 }
 }
 }

 public static double distance(double[] a, double[] b) {
 double sum = 0;
 for (int i = 0; i < a.length; i++) {
 sum += Math.pow(a[i] - b[i], 2);
 }
 return Math.sqrt(sum);
 }
